import com.demo.web.model.Autographs.autograph; public class AutographWriteResponse { private boolean success; private int errorCode; private String displayTitle; private autograph autograph; private String shareToken; private String redirectUrl; public boolean isSuccess() { return success; } public void setSuccess(boolean success) { this.success = success; } public int getErrorCode() { return errorCode; } public void setErrorCode(int errorCode) { this.errorCode = errorCode; } public String getDisplayTitle() { return displayTitle; } public void setDisplayTitle(String displayTitle) { this.displayTitle = displayTitle; } public autograph getAutograph() { return autograph; } public void setAutograph(autograph autograph) { this.autograph = autograph; } public String getShareToken() { return shareToken; } public void setShareToken(String shareToken) { this.shareToken = shareToken; } public String getRedirectUrl() { return redirectUrl; } public void setRedirectUrl(String redirectUrl) { this.redirectUrl = redirectUrl; } }
